{
  "name": "Community Choices Waiver (CCW)",
  "eligibility": {
    "age": 21,
    "income_limits": "Income must meet Louisiana Medicaid long-term care limits, typically $2,742/month for an individual and $5,484/month for a couple (both needing long-term care) as of recent data; older sources cite $2,199 individual/$4,398 couple. Limits subject to annual adjustment. Waiver spend-down option available if over limits. Varies by Medicaid rules, not detailed household size table beyond singles/couples. Must meet Medicaid financial eligibility overall[1][2][4][5].",
    "asset_limits": "Single: $2,000 max resources. Couples (both LTC): $3,000. Couples (one spouse at home): up to $117,240. Exempt: primary home (equity ≤$752,000 in 2026 if intent to return, spouse/minor/disabled child lives there), one vehicle, household furnishings/appliances, personal effects. 60-month look-back rule applies; gifting/selling below market value causes penalty period[2][3].",
    "other_requirements": [
      "Louisiana resident",
      "Meet Nursing Facility Level of Care (NFLOC): inability to perform ADLs like transferring, mobility, eating, toileting; unstable conditions, cognitive issues (e.g., dementia may qualify but diagnosis alone insufficient)",
      "Meet Medicaid long-term care eligibility"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Specific services: Personal care, homemaker, adult day care, home/nursing services, home-delivered meals, caregiver respite/temporary support, housing stabilization/transition/crisis intervention. No 24/7 care; alternative arrangements required. No fixed dollar amounts or hours specified; individualized based on needs[1][3][4][5].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Phone: Call Louisiana Options in Long-Term Care at 1-877-456-1146 to add name to Request for Services Registry",
      "No specific online URL, mail, or in-person detailed; phone is primary route to request slot"
    ],
    "processing_time": "Not specified; offers based on priority and first-come-first-served after registry request",
    "waitlist": "Yes; prioritized by need: 1) APS/EPS abuse/neglect referrals at risk of institutionalization, 2) ALS diagnosis, 3) State Permanent Supportive Housing residents/linked, 4) Nursing facility residents >90 days with Medicaid, 5) Non-recipients of other HCBS waivers. Others first-come-first-served by request date. Expedited for some LT-PCS recipients[1][3][4][5].",
    "forms": ["None specified; request via phone to registry"],
    "documents": ["Not detailed in sources; prepare for Medicaid eligibility: income proof, asset statements, medical records for NFLOC assessment (ADLs, diagnoses). Home equity docs if applicable[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; Louisiana residents",
    "regional_variations": "No regional differences noted in services, providers, or wait times; statewide via OAAS[1][3][5]",
    "offices_or_providers": ["Administered statewide by LA Dept of Health Office of Aging and Adult Services (OAAS)"]
  },
  "official_source": "https://ldh.la.gov/page/community-choices-waiver",
  "gotchas": [
    "No 24/7 care; must arrange separately[1][4]",
    "Priority waitlist means non-priority may wait long; apply immediately[1][4][5]",
    "60-month look-back on assets; penalties for improper transfers[2]",
    "NFLOC required; dementia diagnosis alone insufficient[2]",
    "Income/asset limits strict but spend-down and exemptions available[2][4][5]"
  ],
  "data_shape_notes": "Priority-tiered waitlist drives access; no 24/7 services; asset exemptions detailed with home equity cap; Medicaid LTC financials required (spend-down option); statewide uniform"
}

{
  "name": "State Personal Assistance Services (SPAS) Program",
  "eligibility": {
    "age": 18,
    "income_limits": "Must provide verification of income to show unique economic and social needs; no specific dollar amounts or tables provided in official sources[1][3][4]",
    "asset_limits": "No asset limits specified in program sources[1][3][4]",
    "other_requirements": [
      "Have significant disabilities",
      "Needs goods and/or personal assistance services from this program to prevent or remove the individual from inappropriate placement in an institutional setting or to enhance or maintain the individual's employability",
      "Provides verification of the disability from the treating physician",
      "Is capable of, or has a legal/personal representative capable of, self-direction (hiring, firing, and supervising providers)",
      "Note: Some older sources mention age range 18-60 at inception, with continuation after 60 if eligible, but current official sources state 18 or older[1][4]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Personal Care Assistance, Home Modifications, Vehicle Modifications, Utility and Rental Assistance, Medical Supplies and Equipment, Dental Services, Physical Therapy, Homemaker Services, Assistive Technology; subsidy provided for these services to enhance community living and employability; no specific dollar amounts or hours per week stated[1]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Phone: Call the Arc of Louisiana at 225-383-1033 or 1-866-966-6260[4][5]",
      "Email: spas@thearcla.org[5]",
      "Download SPAS Application Packet from The Arc of Louisiana website[5]"
    ],
    "processing_time": "Evaluation by team determines eligibility; department follows recommendations or notifies within 20 days; annual re-evaluation required; no overall processing timeline specified[3]",
    "waitlist": null,
    "forms": [
      "SPAS Application Packet[5]",
      "SPAS Self-Direction Handbook and Forms (for current clients: Employer Packet, Employee Packet, Employee Timesheet)[5]"
    ],
    "documents": [
      "Verification of disability from treating physician",
      "Verification of income to show unique economic and social needs[1]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": [
      "Administered statewide by Louisiana Department of Health, Office of Aging and Adult Services; services managed by The Arc of Louisiana[1][3][5]"
    ]
  },
  "official_source": "https://ldh.la.gov/office-of-aging-and-adult-services/SPAS[1]",
  "gotchas": [
    "Must be capable of self-direction or have a representative; participant responsible for hiring/firing/supervising providers even if choosing an agency[1][3]",
    "Not the same as LT-PCS Medicaid program, which has strict income/asset limits ($994/month single, $2,000 assets in 2026) and targets elderly/disabled 21+ or 65+ with different criteria[2]",
    "Requires physician verification and evaluation team assessment; income verification needed but not quantified publicly[1]",
    "Aimed at employability and avoiding institutionalization, not general elderly care[1][3]"
  ],
  "data_shape_notes": "Self-directed model where participant manages providers; no public income/asset caps detailed (unlike Medicaid LT-PCS); services via subsidy, not fixed hours/dollars; statewide with central management by Arc of Louisiana"
}
